import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { ResultsProvider } from './context/ResultsContext';
import ProtectedRoute from './components/ProtectedRoute';
import DashboardLayout from './components/DashboardLayout';
import ChatWidget from './components/ChatWidget';
import './styles/global.css';

// Pages
import Landing from './pages/Landing';
import { Login, Register, AdminLogin, ForgotPassword, ResetPassword } from './pages/Auth';
import Dashboard from './pages/Dashboard';
import AdminDashboard from './pages/AdminDashboard';
import AptitudeRound from './pages/AptitudeRound';
import TechnicalRound from './pages/TechnicalRound';
import BreakScreen from './pages/BreakScreen';
import { BehavioralRound, ResultPage, Analytics, Leaderboard, Profile } from './pages/OtherPages';

// ─── Layout Wrapper for dashboard pages ──────────────────────
function WithLayout({ children }) {
  return <DashboardLayout>{children}</DashboardLayout>;
}

// ─── Protected + Layout wrapper ───────────────────────────────
function ProtectedWithLayout({ children, allowRoles }) {
  return (
    <ProtectedRoute allowRoles={allowRoles}>
      <WithLayout>{children}</WithLayout>
    </ProtectedRoute>
  );
}

// ─── Protected WITHOUT layout (full-screen round pages) ───────
function ProtectedNoLayout({ children, allowRoles }) {
  return <ProtectedRoute allowRoles={allowRoles}>{children}</ProtectedRoute>;
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <ResultsProvider>
          <Routes>
            {/* ── Public ── */}
            <Route path="/" element={<Landing />} />
            <Route path="/login" element={<Login />} />
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route path="/register" element={<Register />} />
            <Route path="/forgot-password" element={<ForgotPassword />} />
            <Route path="/reset-password" element={<ResetPassword />} />

            {/* ── Dashboard (with sidebar) ── */}
            <Route path="/dashboard" element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><Dashboard /></ProtectedWithLayout>} />
            <Route path="/admin-dashboard" element={<ProtectedWithLayout allowRoles={['ADMIN']}><AdminDashboard /></ProtectedWithLayout>} />
            <Route path="/analytics"  element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><Analytics /></ProtectedWithLayout>} />
            <Route path="/leaderboard"element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><Leaderboard /></ProtectedWithLayout>} />
            <Route path="/profile"    element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><Profile /></ProtectedWithLayout>} />

            {/* ── Round Result pages (with sidebar) ── */}
            <Route path="/aptitude/result"  element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><ResultPage type="aptitude" /></ProtectedWithLayout>} />
            <Route path="/technical/result" element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><ResultPage type="technical" /></ProtectedWithLayout>} />
            <Route path="/behavioral/result"element={<ProtectedWithLayout allowRoles={['CANDIDATE', 'ADMIN']}><ResultPage type="behavioral" /></ProtectedWithLayout>} />

            {/* ── Round pages (full-screen, no sidebar) ── */}
            <Route path="/aptitude"  element={<ProtectedNoLayout allowRoles={['CANDIDATE', 'ADMIN']}><AptitudeRound /></ProtectedNoLayout>} />
            <Route path="/technical" element={<ProtectedNoLayout allowRoles={['CANDIDATE', 'ADMIN']}><TechnicalRound /></ProtectedNoLayout>} />
            <Route path="/technical-round" element={<ProtectedNoLayout allowRoles={['CANDIDATE', 'ADMIN']}><TechnicalRound /></ProtectedNoLayout>} />
            <Route path="/behavioral"element={<ProtectedNoLayout allowRoles={['CANDIDATE', 'ADMIN']}><BehavioralRound /></ProtectedNoLayout>} />
            <Route path="/break"     element={<ProtectedNoLayout allowRoles={['CANDIDATE', 'ADMIN']}><BreakScreen /></ProtectedNoLayout>} />

            {/* ── Catch all ── */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
          <ChatWidget />
        </ResultsProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
